remediation.terraform:
# Ensure the RDS instance is not publicly accessible
resource "aws_db_instance" "<example_resource_name>" {
  publicly_accessible = false  # CRITICAL: disables public access (no public endpoint)
}

# Assign RDS clusters to an existing AWS Backup plan
resource "aws_backup_selection" "<example_resource_name>" {
  name         = "rds-clusters"
  plan_id      = "<example_backup_plan_id>"
  iam_role_arn = "arn:aws:iam::<example_account_id>:role/service-role/AWSBackupDefaultServiceRole"

  resources = [
    "arn:aws:rds:*:*:cluster:*" # Critical: includes all RDS clusters in the plan to pass the check
  ]
}

# Set a current CA on the RDS instance
resource "aws_db_instance" "<example_resource_name>" {
  identifier          = "<example_resource_id>"
  ca_cert_identifier  = "rds-ca-rsa2048-g1"  # CRITICAL: rotates to a valid CA to ensure certificate validity >3 months
}

# Terraform: ensure RDS instance is in a VPC via DB subnet group
resource "aws_db_subnet_group" "<example_resource_name>" {
  name       = "<example_resource_name>"
  subnet_ids = [
    "<example_resource_id>", # CRITICAL: Subnets in the target VPC
    "<example_resource_id>"
  ]
}

resource "aws_db_instance" "<example_resource_name>" {
  identifier          = "<example_resource_id>"
  db_subnet_group_name = aws_db_subnet_group.<example_resource_name>.name  # CRITICAL: Places instance in a VPC
}

# DB instances
resource "aws_db_parameter_group" "example_pg" {
  name   = "<example_resource_name>"
  family = "<DB_PARAMETER_FAMILY>"

  parameter {
    name  = "rds.force_ssl"
    value = "1"  # Critical: requires SSL/TLS for PostgreSQL/SQL Server instances
  }
}

resource "aws_db_parameter_group" "example_mysql" {
  name   = "<example_resource_name>"
  family = "<DB_PARAMETER_FAMILY>"

  parameter {
    name  = "require_secure_transport"
    value = "1"  # Critical: requires SSL/TLS for MySQL/MariaDB instances
  }
}

# Aurora clusters
resource "aws_rds_cluster_parameter_group" "example_aurora_pg" {
  name   = "<example_resource_name>"
  family = "<DB_CLUSTER_PARAMETER_FAMILY>"

  parameter {
    name  = "rds.force_ssl"
    value = "1"  # Critical: requires SSL/TLS for Aurora PostgreSQL clusters
  }
}

resource "aws_rds_cluster_parameter_group" "example_aurora_mysql" {
  name   = "<example_resource_name>"
  family = "<DB_CLUSTER_PARAMETER_FAMILY>"

  parameter {
    name  = "require_secure_transport"
    value = "ON"  # Critical: requires SSL/TLS for Aurora MySQL clusters
  }
}

resource "aws_db_snapshot_copy" "<example_resource_name>" {
  source_db_snapshot_identifier = "<example_resource_id>"
  target_db_snapshot_identifier = "<example_resource_id>-encrypted"
  kms_key_id                    = "<KMS_KEY_ID>" # Critical: encrypts the copied snapshot using the specified KMS key
}

# Enable deletion protection on an existing RDS DB Cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  deletion_protection = true  # Critical: prevents cluster deletion and passes the check
}

# Enable IAM authentication on an existing RDS/Aurora cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  cluster_identifier                   = "<example_resource_id>"
  iam_database_authentication_enabled = true  # Critical: enables IAM DB auth so the check passes
}

# Terraform: Enable CloudWatch Logs export for an RDS/Aurora DB cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  engine            = "<engine>"
  master_username   = "<example_username>"
  master_password   = "<example_password>"

  enabled_cloudwatch_logs_exports = [
    "<engine_supported_log_type>" # CRITICAL: Enables at least one supported log type (e.g., "error" for MySQL or "postgresql" for PostgreSQL) to pass the check
  ]
}

# Terraform snippet to enable automatic minor version upgrades on an RDS DB cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  cluster_identifier         = "<example_resource_id>"
  auto_minor_version_upgrade = true  # Critical: enables automatic minor engine version upgrades to pass the check
}

# Enable deletion protection on a standalone RDS instance
resource "aws_db_instance" "<example_resource_name>" {
  deletion_protection = true  # Critical: prevents instance deletion
}

# Enable deletion protection on an RDS/Aurora cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  deletion_protection = true  # Critical: prevents cluster deletion (required for instances in this cluster)
}

resource "aws_db_event_subscription" "<example_resource_name>" {
  name            = "<example_resource_name>"
  sns_topic       = "<SNS_TOPIC_ARN>"
  source_type     = "db-security-group"        # Critical: DB security group events
  event_categories = ["configuration change", "failure"]  # Critical: required categories
}

# Enable IAM DB authentication on an RDS instance
resource "aws_db_instance" "<example_resource_name>" {
  iam_database_authentication_enabled = true  # Critical: enables IAM DB auth to pass the check
}

resource "aws_db_instance" "<example_resource_name>" {
  identifier = "<example_resource_id>"
  # Critical: export at least one supported log type to CloudWatch Logs to pass the check
  enabled_cloudwatch_logs_exports = ["<log_type>"]
}

# Enable Multi-AZ on an RDS DB instance
resource "aws_db_instance" "example" {
  multi_az = true  # Critical: enables Multi-AZ to pass the check
}

# Terraform: enable copying tags to snapshots on an RDS DB cluster
resource "aws_rds_cluster" "<example_resource_name>" {
  copy_tags_to_snapshot = true  # CRITICAL: ensures cluster tags are copied to snapshots
}

# Terraform: enable copying tags to snapshots on an RDS DB instance
resource "aws_db_instance" "<example_resource_name>" {
  copy_tags_to_snapshot = true  # Critical: ensures DB instance tags are copied to snapshots
}

# Enable Enhanced Monitoring on an existing RDS instance
resource "aws_db_instance" "<example_resource_name>" {
  # ...existing required configuration...
  monitoring_role_arn = "<monitoring_role_arn>"  # CRITICAL: Role for publishing OS metrics
  monitoring_interval = 60                        # CRITICAL: >0 enables Enhanced Monitoring (seconds)
}

resource "aws_db_event_subscription" "<example_resource_name>" {
  name             = "<example_resource_name>"
  sns_topic        = "<sns-topic-arn>"
  source_type      = "db-parameter-group"          # Critical: target DB parameter groups
  event_categories = ["configuration change"]       # Critical: include configuration change events
}

# Terraform: set a non-default port on an RDS instance
resource "aws_db_instance" "<example_resource_name>" {
  port = <non-default-port>  # Critical: use a non-default DB engine port to pass the check
}
